// MARK: - Keychain Helper
class KeychainManager {
    
    static let shared = KeychainManager()
    private init() {}
    
    private let service = "com.myapp.authentication"
    private let authenticatedKey = "isAuthenticated"
    private let biometricEnabledKey = "biometricEnabled"
    
    func save(key: String, value: String) -> Bool {
        guard let data = value.data(using: .utf8) else { return false }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        
        SecItemDelete(query as CFDictionary)
        
        var newItem = query
        newItem[kSecValueData as String] = data
        
        let status = SecItemAdd(newItem as CFDictionary, nil)
        return status == errSecSuccess
    }
    
    func retrieve(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
    
    func delete(key: String) -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        let status = SecItemDelete(query as CFDictionary)
        return status == errSecSuccess || status == errSecItemNotFound
    }
    
    var isAuthenticated: Bool {
        get { return retrieve(key: authenticatedKey) == "true" }
        set {
            if newValue {
                _ = save(key: authenticatedKey, value: "true")
            } else {
                _ = delete(key: authenticatedKey)
            }
        }
    }
    
    var isBiometricEnabled: Bool {
        get { return retrieve(key: biometricEnabledKey) == "true" }
        set {
            if newValue {
                _ = save(key: biometricEnabledKey, value: "true")
            } else {
                _ = delete(key: biometricEnabledKey)
            }
        }
    }
}

// MARK: - Biometric Authentication Manager
class BiometricAuthManager {
    
    static let shared = BiometricAuthManager()
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
        case opticID
    }
    
    enum AuthenticationError: Error, LocalizedError {
        case biometricNotAvailable
        case biometricNotEnrolled
        case authenticationFailed
        case userCancelled
        case userFallback
        case systemCancel
        case passcodeNotSet
        case unknown(Error)
        
        var errorDescription: String? {
            switch self {
            case .biometricNotAvailable:
                return "Biometric authentication is not available on this device."
            case .biometricNotEnrolled:
                return "No biometric data is enrolled. Please set up Face ID or Touch ID in Settings."
            case .authenticationFailed:
                return "Authentication failed. Please try again."
            case .userCancelled:
                return "Authentication was cancelled."
            case .userFallback:
                return "User chose to enter password."
            case .systemCancel:
                return "Authentication was cancelled by the system."
            case .passcodeNotSet:
                return "Device passcode is not set. Please set a passcode in Settings."
            case .unknown(let error):
                return error.localizedDescription
            }
        }
    }
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .opticID
        case .none:
            return .none
        @unknown default:
            return .none
        }
    }
    
    var biometricTypeString: String {
        switch biometricType {
        case .faceID: return "Face ID"
        case .touchID: return "Touch ID"
        case .opticID: return "Optic ID"
        case .none: return "Biometrics"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    func authenticate(reason: String? = nil, completion: @escaping (Result<Bool, AuthenticationError>) -> Void) {
        let context = LAContext()
        context.localizedFallbackTitle = "Enter Password"
        context.localizedCancelTitle = "Cancel"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            let authError = mapLAError(error)
            DispatchQueue.main.async {
                completion(.failure(authError))
            }
            return
        }
        
        let authReason = reason ?? "Authenticate with \(biometricTypeString) to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: authReason) { success, evaluationError in
            DispatchQueue.main.async {
                if success {
                    KeychainManager.shared.isAuthenticated = true
                    completion(.success(true))
                } else if let error = evaluationError as? LAError {
                    let authError = self.mapLAErrorCode(error.code)
                    completion(.failure(authError))
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
    
    private func mapLAError(_ error: NSError?) -> AuthenticationError {
        guard let error = error else { return .unknown(NSError(domain: "", code: -1)) }
        
        if let laError = error as? LAError {
            return mapLAErrorCode(laError.code)
        }
        
        return mapLAErrorCode(LAError.Code(rawValue: error.code) ?? .authenticationFailed)
    }
    
    private func mapLAErrorCode(_ code: LAError.Code) -> AuthenticationError {
        switch code {
        case .biometryNotAvailable:
            return .biometricNotAvailable
        case .biometryNotEnrolled:
            return .biometricNotEnrolled
        case .authenticationFailed:
            return .authenticationFailed
        case .userCancel:
            return .userCancelled
        case .userFallback:
            return .userFallback
        case .systemCancel:
            return .systemCancel
        case .passcodeNotSet:
            return .passcodeNotSet
        default:
            return .authenticationFailed
        }
    }
    
    func logout() {
        KeychainManager.shared.isAuthenticated = false
    }
}

