// MARK: - App Flow Coordinator
class AppFlowCoordinator {
    
    static let shared = AppFlowCoordinator()
    private init() {}
    
    func determineInitialViewController() -> UIViewController {
        if KeychainManager.shared.isAuthenticated && KeychainManager.shared.isBiometricEnabled {
            // User was previously authenticated and has biometric enabled
            // Show login screen but auto-trigger biometric
            return LoginViewController()
        } else if KeychainManager.shared.isAuthenticated {
            // User is authenticated (session still valid) but no biometric
            // Go directly to main screen
            return UINavigationController(rootViewController: MainViewController())
        } else {
            // Fresh login required
            return LoginViewController()
        }
    }
}

// MARK: - SceneDelegate Integration
class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        window = UIWindow(windowScene: windowScene)
        window?.rootViewController = AppFlowCoordinator.shared.determineInitialViewController()
        window?.makeKeyAndVisible()
    }
    
    func sceneDidBecomeActive(_ scene: UIScene) {
        // Optionally re-authenticate when app becomes active after being in background
    }
    
    func sceneWillResignActive(_ scene: UIScene) {
        // Optionally add a privacy overlay
    }
}

